// ── shAC — Universele autocomplete engine ────────────────────────────────────
window.shAC = (function(){
  let _inp = null, _items = [], _cb = null, _sel = -1;
  let _box = null;

  function _ensureBox(){
    if(_box && document.body.contains(_box)) return;
    _box = document.createElement('div');
    _box.className = 'sh-ac-box';
    _box.style.cssText = 'position:fixed;z-index:99999;background:var(--bg-card,#1a1e2e);border:1px solid var(--border,#2a2f45);border-radius:10px;box-shadow:0 8px 32px rgba(0,0,0,.45);overflow:hidden;max-height:240px;overflow-y:auto;min-width:200px;';
    document.body.appendChild(_box);
    _box.addEventListener('mousedown', e => {
      const li = e.target.closest('[data-ac-idx]');
      if(li){ e.preventDefault(); _pick(+li.dataset.acIdx); }
    });
  }

  function _pos(){
    if(!_inp || !_box) return;
    const r    = _inp.getBoundingClientRect();
    const vv   = window.visualViewport;
    // visualViewport.offsetTop = hoeveel de viewport verschoven is door keyboard/pinch
    const vvOffsetTop  = vv ? vv.offsetTop  : 0;
    const vvOffsetLeft = vv ? vv.offsetLeft : 0;
    const vvH          = vv ? vv.height     : window.innerHeight;

    // r.bottom / r.top zijn viewport-coordinaten (relatief aan bovenkant zichtbaar scherm)
    // We zetten de box op fixed positie, dus we rekenen in viewport-coords
    const boxH     = Math.min(_items.length * 44, 240);
    const spaceBelow = vvH - r.bottom;
    const spaceAbove = r.top;

    // Altijd naar BENEDEN tenzij er echt te weinig ruimte is én boven meer ruimte is
    const goUp = (spaceBelow < boxH) && (spaceAbove > spaceBelow);
    const top  = goUp
      ? r.top  + vvOffsetTop  - boxH - 4
      : r.bottom + vvOffsetTop + 2;
    const left = r.left + vvOffsetLeft;

    _box.style.position = 'fixed';
    _box.style.left     = Math.max(0, left) + 'px';
    _box.style.top      = Math.max(0, top)  + 'px';
    _box.style.width    = Math.max(r.width, 220) + 'px';
  }

  function _render(){
    if(!_box) return;
    _box.innerHTML = _items.map((it,i) => {
      const primary = escapeHtml(it.primary || it.label || '');
      const secondary = it.secondary ? `<div style="font-size:11px;color:var(--text-2,#9aa3b7);margin-top:1px;">${escapeHtml(it.secondary)}</div>` : '';
      const bg = i === _sel ? 'background:var(--hover,#1e2236);' : '';
      return `<div data-ac-idx="${i}" style="padding:9px 14px;cursor:pointer;${bg}" onmouseover="this.style.background='var(--hover,#1e2236)'" onmouseout="this.style.background='${i===_sel?'var(--hover,#1e2236)':''}'">
        <div style="font-size:14px;color:var(--text-1,#e2e8f0);font-weight:500;">${primary}</div>${secondary}
      </div>`;
    }).join('');
  }

  function _pick(idx){
    if(idx < 0 || idx >= _items.length) return;
    if(_cb) _cb(_items[idx]);
    _close();
  }

  function _close(){
    _sel = -1;
    _items = [];
    _inp = null;
    _cb = null;
    if(_box){ _box.innerHTML = ''; _box.style.display = 'none'; }
  }

  // Herpositioneer bij toetsenbord open/dicht (iOS visualViewport)
  if(window.visualViewport){
    window.visualViewport.addEventListener('resize', () => { if(_inp && _box) _pos(); });
    window.visualViewport.addEventListener('scroll', () => { if(_inp && _box) _pos(); });
  }

  return {
    show(input, items, cb){
      _ensureBox();
      _inp = input; _items = items; _cb = cb; _sel = -1;
      _box.style.display = 'block';
      _pos();
      _render();
    },
    close: _close,
    onKey(e){
      if(!_items.length) return false;
      if(e.key === 'ArrowDown'){ _sel = Math.min(_sel+1, _items.length-1); _render(); return true; }
      if(e.key === 'ArrowUp'){ _sel = Math.max(_sel-1, -1); _render(); return true; }
      if(e.key === 'Enter' && _sel >= 0){ _pick(_sel); return true; }
      if(e.key === 'Escape'){ _close(); return true; }
      return false;
    }
  };
  window.addEventListener('resize', () => { if(_inp) _close(); }, true);
})();


/* ================================================================
   TOERNOOI-FUNCTIONALITEIT — v1.0
   Datamodel: Tournament, TournamentDay, TournamentTeam, Match,
   TournamentPlayer, MatchPlayer, Observation, PlayerTournamentSummary
   Gebaseerd op ontwerp v1.2
   ================================================================ */

// ── Caches ──────────────────────────────────────────────────────
let tourmCache = [];          // lijst van tournaments (top-level docs)
let _currentTournamentId = null;
let _currentTournamentData = null; // { tournament, days, teams, matches, players, matchPlayers }
let unsubTournaments = null;

// ── Collection helpers ───────────────────────────────────────────
function tournamentsCol(){
  return collection(db, 'users', currentUser.uid, 'tournaments');
}
function tournSubCol(tid, sub){
  return collection(db, 'users', currentUser.uid, 'tournaments', tid, sub);
}
function tournDoc(tid){
  return doc(db, 'users', currentUser.uid, 'tournaments', tid);
}
function tournSubDoc(tid, sub, id){
  return doc(db, 'users', currentUser.uid, 'tournaments', tid, sub, id);
}

// ── ID generator (prefix t_) ─────────────────────────────────────
function tuid(prefix='t'){
  return prefix + '_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8);
}

// Placeholder-speler herkennen: de import maakt per team één markeerspeler
// "Speler — <Teamnaam>" (geen playerId) zodat de scout direct kan toevoegen.
// Deze placeholders mogen NIET als echte spelers worden getoond.
function isPlaceholderTournamentPlayer(tp){
  if(!tp || typeof tp !== 'object') return false;
  if(tp.playerId) return false;                 // gekoppeld aan DB-profiel = echt
  const nm = String(tp.quickName == null ? '' : tp.quickName).trim();
  return /^Speler\s*[—–-]\s*\S/.test(nm);        // "Speler — Teamnaam"
}
window.isPlaceholderTournamentPlayer = isPlaceholderTournamentPlayer;

// ── Subscribe tournaments (top-level lijst) ─────────────────────
function subscribeTournaments(){
  if(unsubTournaments) return;
  if(typeof __shTrace === 'function') __shTrace('tournaments-subscribe-start', { uid: currentUser && currentUser.uid });
  unsubTournaments = onSnapshot(tournamentsCol(), snap => {
    tourmCache = snap.docs.map(d => ({...d.data(), id: d.id}))
      .sort((a,b) => (b.startDate||'').localeCompare(a.startDate||''));
    if(typeof __shTrace === 'function') __shTrace('tournaments-subscribe-ok', { count: tourmCache.length });
    if(currentView === 'toernooien' && !_currentTournamentId) renderToernooienList();
    // Feature 15: programma-kaarten verversen zodra tourmCache binnen is
    if(currentView === 'programma' && typeof _renderProgrammaToernooiCards === 'function') _renderProgrammaToernooiCards();
    setSync('ok');
  }, err => {
    console.error('Tournaments sync error:', err);
    if(typeof __shTrace === 'function') __shTrace('tournaments-subscribe-error', { msg: err && err.message, code: err && err.code });
    // Toon fallback in UI als de view open staat
    if(currentView === 'toernooien'){
      const wrap = document.getElementById('toern-list-wrap');
      if(wrap){
        const isPermission = err && (err.code === 'permission-denied' || (err.message||'').includes('permissions'));
        wrap.innerHTML = isPermission
          ? '<div class="toern-empty" style="border-color:var(--red);color:var(--red);">⚠️ Geen toegang tot toernooien-data.<br><small>Controleer Firestore-regels voor <code>users/{uid}/tournaments</code>.</small></div>'
          : `<div class="toern-empty" style="border-color:var(--red);">Fout bij laden: ${err.message || 'onbekend'}</div>`;
      }
    }
    // Reset subscribe-guard zodat retry mogelijk is
    unsubTournaments = null;
    setSync('offline');
  });
}

// ── Tournament CRUD ──────────────────────────────────────────────
async function saveTournament(t){
  setSync('syncing');
  try {
    const id = t.id;
    const {id: _drop, ...data} = t;
    await setDoc(tournDoc(id), data);
  } catch(e){
    console.error('saveTournament error:', e);
    toast('Opslaan mislukt', true);
    setSync('offline');
    throw e;
  }
}

async function createTournament({ name, location='', startDate='', endDate='', categories=[], info='' }){
  const id = tuid('toern');
  const t = {
    id, name, location,
    startDate: startDate || todayISO(),
    endDate: endDate || startDate || todayISO(),
    categories,
    info,
    status: 'prep',
    createdBy: currentUser.uid,
    createdAt: new Date().toISOString(),
    tournifyData: null
  };
  await saveTournament(t);
  return t;
}

async function deleteTournament(id){
  setSync('syncing');
  try { await deleteDoc(tournDoc(id)); }
  catch(e){ toast('Verwijderen mislukt', true); setSync('offline'); throw e; }
}

// Recursief verwijderen: alle subcollecties van DIT toernooi + het doc zelf.
// Raakt uitsluitend het geselecteerde toernooi (users/{uid}/tournaments/{id}/...).
async function deleteTournamentDeep(id){
  setSync('syncing');
  const subs = ['matchPlayers', 'observations', 'summaries', 'players', 'matches', 'days', 'teams'];
  try {
    for(const sub of subs){
      const snap = await getDocs(tournSubCol(id, sub));
      const ids = snap.docs.map(d => d.id);
      // In brokjes verwijderen zodat grote toernooien niet vastlopen
      for(let i = 0; i < ids.length; i += 20){
        await Promise.all(ids.slice(i, i + 20).map(docId => deleteDoc(tournSubDoc(id, sub, docId))));
      }
    }
    await deleteDoc(tournDoc(id));
    setSync('ok');
  } catch(e){
    console.error('deleteTournamentDeep error:', e);
    toast('Verwijderen mislukt: ' + (e.message || e), true);
    setSync('offline');
    throw e;
  }
}
window.deleteTournamentDeep = deleteTournamentDeep;

// Bevestig + verwijder het huidige toernooi vanuit het detailscherm.
async function confirmDeleteTournament(id){
  id = id || _currentTournamentId || (typeof window !== 'undefined' ? window._currentTournamentId : null);
  if(!id){ toast('Geen toernooi geselecteerd', true); return; }
  const t = tourmCache.find(x => x.id === id);
  const naam = t ? (t.name || 'dit toernooi') : 'dit toernooi';
  // K1: tel onderliggende data (read-only) voor de waarschuwing
  let _nM = 0, _nP = 0, _nO = 0;
  try {
    const [_ms, _ps, _os] = await Promise.all([
      getDocs(tournSubCol(id, 'matches')),
      getDocs(tournSubCol(id, 'players')),
      getDocs(tournSubCol(id, 'observations'))
    ]);
    _nM = _ms.size; _nP = _ps.size; _nO = _os.size;
  } catch(_){}
  // K1: typed-confirm — toernooinaam exact typen (zelfde drempel als spelersrapport-delete)
  const _ok = await showTypedDeleteConfirm({
    title: 'Toernooi verwijderen?',
    body: `Je staat op het punt <b>${String(naam).replace(/</g,'&lt;')}</b> permanent te verwijderen.<br><br>Hiermee verdwijnen <b>${_nM}</b> wedstrijd${_nM===1?'':'en'}, <b>${_nP}</b> speler${_nP===1?'':'s'} en <b>${_nO}</b> observatie${_nO===1?'':'s'} — onomkeerbaar.`,
    label: 'Type de toernooinaam om te bevestigen:',
    confirmWord: naam
  });
  if(!_ok) return;
  try {
    await deleteTournamentDeep(id);
    toast('Toernooi verwijderd');
    backToTournamentList();
  } catch(_){ /* fout al getoast */ }
}
window.confirmDeleteTournament = confirmDeleteTournament;

// ── Days ─────────────────────────────────────────────────────────
async function saveDay(tid, day){
  setSync('syncing');
  try {
    const id = day.id;
    const {id: _drop, ...data} = day;
    await setDoc(tournSubDoc(tid, 'days', id), data);
  } catch(e){ toast('Dag opslaan mislukt', true); setSync('offline'); throw e; }
}

async function addDay(tid, { date='', label='' }){
  const id = tuid('day');
  const day = { id, tournamentId: tid, date: date || todayISO(), label: label || 'Dag 1', closedAt: null, editHistory: [] };
  await saveDay(tid, day);
  return day;
}

async function closeDay(tid, dayId){
  // Sluit dag: zet closedAt op dag + alle observaties van die dag
  const now = new Date().toISOString();
  await setDoc(tournSubDoc(tid, 'days', dayId), { closedAt: now }, { merge: true });
  // Haal observaties op voor die dag en zet closedAt
  const obsSnap = await getDocs(query(tournSubCol(tid, 'observations'), where('dayId','==',dayId)));
  const batch = [];
  obsSnap.docs.forEach(d => {
    if(!d.data().closedAt){
      batch.push(setDoc(doc(tournSubCol(tid, 'observations'), d.id), { closedAt: now }, { merge: true }));
    }
  });
  await Promise.all(batch);
  // Genereer concept-bundeling per speler
  await generateDaySummaries(tid, dayId);
  toast('Dag afgesloten ✓');
}

async function reopenDay(tid, dayId){
  // Blokkeer heropenen als er al een definitief rapport uit die dag's bundeling is gemaakt
  const summSnap = await getDocs(query(tournSubCol(tid, 'summaries'), where('dayBlocks','array-contains',dayId)));
  // Simpele check: bestaat er een summary met status 'done' die deze dag bevat?
  const blocked = summSnap.docs.some(d => {
    const s = d.data();
    return s.reportCreated === true;
  });
  if(blocked){
    toast('Rapport al aangemaakt — bundeling is vergrendeld', true);
    return false;
  }
  await setDoc(tournSubDoc(tid, 'days', dayId), { closedAt: null }, { merge: true });
  // Zet summaries met dayBlock voor deze dag terug naar 'edited' als ze 'ready' waren
  const allSumm = await getDocs(tournSubCol(tid, 'summaries'));
  const updates = [];
  allSumm.docs.forEach(d => {
    const s = d.data();
    const hasDay = (s.dayBlocks||[]).some(b => b.dayId === dayId);
    if(hasDay && s.status === 'ready'){
      updates.push(setDoc(doc(tournSubCol(tid, 'summaries'), d.id), { status: 'edited', reopenedAt: new Date().toISOString() }, { merge: true }));
    }
  });
  await Promise.all(updates);
  toast('Dag heropend — observaties zijn weer bewerkbaar');
  return true;
}

