// Feature 4 — naar vorige/volgende wedstrijd binnen het tijdsblok.
function navMatch(dir){
  const nv = window._matchNav; if(!nv || !nv.ids) return;
  const ni = nv.idx + dir;
  if(ni < 0 || ni >= nv.ids.length) return;
  openMatchDetail(nv.tid, nv.ids[ni]);
}
